@namespace sv_178cd43f727c4bbaaeb14e6be97be172.Components.JobApplication

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex list-unstyled justify-content-between position-relative step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var cssClass = isCurrent ? "active" : isCompleted ? "completed" : "pending";

            <li class="step-item @cssClass text-center flex-fill">
                @if (isCompleted && !isCurrent)
                {
                    <button class="btn btn-link p-0 text-decoration-none w-100" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle d-inline-flex align-items-center justify-content-center rounded-circle mb-1">
                            <span>&#10003;</span>
                        </span>
                        <span class="step-label d-block small">@StepNames[step - 1]</span>
                    </button>
                }
                else
                {
                    <div>
                        <span class="step-circle d-inline-flex align-items-center justify-content-center rounded-circle mb-1">
                            @step
                        </span>
                        <span class="step-label d-block small">@StepNames[step - 1]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator .step-list {
    counter-reset: step;
    gap: 0.25rem;
}

.step-circle {
    width: 36px;
    height: 36px;
    font-weight: 600;
    font-size: 0.9rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #adb5bd;
    transition: all 0.2s;
}

.step-item.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.pending .step-label {
    color: #adb5bd;
}

@namespace sv_178cd43f727c4bbaaeb14e6be97be172.Components.JobApplication

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">
                    Remove
                </button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Company"
                       @onchange="e => { Company = (string?)e.Value ?? string.Empty; NotifyChanged(); }" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control" value="@Title"
                       @onchange="e => { Title = (string?)e.Value ?? string.Empty; NotifyChanged(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@StartDate?.ToString("yyyy-MM-dd")"
                       @onchange="e => { StartDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null; NotifyChanged(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@EndDate?.ToString("yyyy-MM-dd")"
                       disabled="@IsCurrent"
                       @onchange="e => { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null; NotifyChanged(); }" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="current-@Index" checked="@IsCurrent"
                           @onchange="e => { IsCurrent = (bool)(e.Value ?? false); if (IsCurrent) EndDate = null; NotifyChanged(); }" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Description"
                          @onchange="e => { Description = (string?)e.Value ?? string.Empty; NotifyChanged(); }"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public int Index { get; set; }
    [Parameter] public string Company { get; set; } = string.Empty;
    [Parameter] public string Title { get; set; } = string.Empty;
    [Parameter] public DateTime? StartDate { get; set; }
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public string Description { get; set; } = string.Empty;
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryData> OnChanged { get; set; }

    private void NotifyChanged()
    {
        OnChanged.InvokeAsync(new WorkEntryData(Company, Title, StartDate, EndDate, IsCurrent, Description));
    }

    public record WorkEntryData(string Company, string Title, DateTime? StartDate, DateTime? EndDate, bool IsCurrent, string Description);
}

