@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private void UpdateEntry(int index, WorkEntryForm.WorkEntryData data)
    {
        if (index < Entries.Count)
        {
            Entries[index] = new WorkEntryModel
            {
                Company = data.Company,
                Title = data.Title,
                StartDate = data.StartDate,
                EndDate = data.EndDate,
                IsCurrent = data.IsCurrent,
                Description = data.Description
            };
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate is null)
            {
                ErrorMessage = "Company, job title, and start date are required for each position.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime? StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }
}

