{"file_text": "@namespace sv_178cd43f727c4bbaaeb14e6be97be172.Components.JobApplication

<h5 class="mb-3">Work History</h5>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <WorkEntryForm Index="index"
                   Company="@entry.Company"
                   Title="@entry.Title"
                   StartDate="@entry.StartDate"
                   EndDate="@entry.EndDate"
                   IsCurrent="@entry.IsCurrent"
                   Description="@entry.Description"
                   ShowRemove="@(Entries.Count > 1)"
                   OnRemove="() => RemoveEntry(index)"
                   OnChanged="data => UpdateEntry(index, data)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter] public EventCallback<List<WorkEntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private void UpdateEntry(int index, WorkEntryForm.WorkEntryData data)
    {
        if (index < Entries.Count)
        {
            Entries[index] = new WorkEntryModel
            {
                Company = data.Company,
                Title = data.Title,
                StartDate = data.StartDate,
                EndDate = data.EndDate,
                IsCurrent = data.IsCurrent,
                Description = data.Description
            };
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate is null)
            {
                ErrorMessage = "Company, job title, and start date are required for each position.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = string.Empty;
        public string Title { get; set; } = string.Empty;
        public DateTime? StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = string.Empty;
    }
}
