@namespace sv_178cd43f727c4bbaaeb14e6be97be172.Components.JobApplication

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex list-unstyled justify-content-between position-relative step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var cssClass = isCurrent ? "active" : isCompleted ? "completed" : "pending";

            <li class="step-item @cssClass text-center flex-fill">
                @if (isCompleted && !isCurrent)
                {
                    <button class="btn btn-link p-0 text-decoration-none w-100" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle d-inline-flex align-items-center justify-content-center rounded-circle mb-1">
                            <span>&#10003;</span>
                        </span>
                        <span class="step-label d-block small">@StepNames[step - 1]</span>
                    </button>
                }
                else
                {
                    <div>
                        <span class="step-circle d-inline-flex align-items-center justify-content-center rounded-circle mb-1">
                            @step
                        </span>
                        <span class="step-label d-block small">@StepNames[step - 1]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

