}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@FullName"
               @onchange="e => FullName = (string?)e.Value ?? string.Empty" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(emailInvalid ? "is-invalid" : "")" value="@Email"
               @onchange="e => { Email = (string?)e.Value ?? string.Empty; emailInvalid = false; }" />
        @if (emailInvalid)
        {
            <div class="invalid-feedback">Please enter a valid email address.</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Phone"
               @onchange="e => Phone = (string?)e.Value ?? string.Empty" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Address"
               @onchange="e => Address = (string?)e.Value ?? string.Empty" />
    </div>
</div>

<div class="d-flex justify-content-end mt-4">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = string.Empty;
    [Parameter] public string Email { get; set; } = string.Empty;
    [Parameter] public string Phone { get; set; } = string.Empty;
    [Parameter] public string Address { get; set; } = string.Empty;
    [Parameter] public EventCallback<PersonalInfoResult> OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? ErrorMessage;
    private bool emailInvalid;
    private bool isValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;
        emailInvalid = false;

        if (string.IsNullOrWhiteSpace(FullName) || string.IsNullOrWhiteSpace(Email)
            || string.IsNullOrWhiteSpace(Phone) || string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "All fields are required.";
            return;
        }

        if (ValidateEmail is not null)
        {
            isValidating = true;
            StateHasChanged();

            var isValid = await ValidateEmail(Email);
            isValidating = false;

            if (!isValid)
            {
                emailInvalid = true;
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }

        await OnNext.InvokeAsync(new PersonalInfoResult(FullName, Email, Phone, Address));
    }

    public record PersonalInfoResult(string FullName, string Email, string Phone, string Address);
}

