@namespace sv_178cd43f727c4bbaaeb14e6be97be172.Components.JobApplication

<h5 class="mb-3">References</h5>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var r = References[index];

    <ReferenceForm Index="index"
                   Name="@r.Name"
                   Relationship="@r.Relationship"
                   Email="@r.Email"
                   Phone="@r.Phone"
                   ShowRemove="@(References.Count > 2)"
                   OnRemove="() => RemoveReference(index)"
                   OnChanged="data => UpdateReference(index, data)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback<List<ReferenceModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private void UpdateReference(int index, ReferenceForm.ReferenceData data)
    {
        if (index < References.Count)
        {
            References[index] = new ReferenceModel
            {
                Name = data.Name,
                Relationship = data.Relationship,
                Email = data.Email,
                Phone = data.Phone
            };
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All fields are required for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync(References);
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = string.Empty;
        public string Relationship { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
        public string Phone { get; set; } = string.Empty;
    }
}

