@namespace sv_178cd43f727c4bbaaeb14e6be97be172.Components.JobApplication

<h5 class="mb-3">Cover Letter</h5>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="10" maxlength="@MaxLength" value="@CoverLetter"
              @oninput="HandleInput"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private void HandleInput(ChangeEventArgs e)
    {
        var value = (string?)e.Value ?? string.Empty;
        CoverLetter = value.Length > MaxLength ? value[..MaxLength] : value;
    }

    private async Task HandleNext()
    {
        await OnNext.InvokeAsync(CoverLetter);
    }
}

