@page "/apply"
@using sv_178cd43f727c4bbaaeb14e6be97be172.Components.JobApplication
@using sv_178cd43f727c4bbaaeb14e6be97be172.Models
@using sv_178cd43f727c4bbaaeb14e6be97be172.Services
@inject IApplicationService ApplicationService
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h3 class="mb-4">Job Application</h3>

    <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                  ValidateEmail="ApplicationService.ValidateEmailAsync"
                                  OnNext="HandlePersonalInfoNext" />
                break;

            case 2:
                <WorkHistoryStep Entries="workEntries" OnNext="HandleWorkHistoryNext" OnBack="GoBack" />
                break;

            case 3:
                <ReferencesStep References="references" OnNext="HandleReferencesNext" OnBack="GoBack" />
                break;

            case 4:
                <CoverLetterStep CoverLetter="@coverLetter" OnNext="HandleCoverLetterNext" OnBack="GoBack" />
                break;

            case 5:
                <ReviewStep FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                            WorkEntries="workEntries" References="references" CoverLetter="@coverLetter"
                            IsSubmitting="isSubmitting" IsSubmitted="isSubmitted" ApplicationId="applicationId"
                            OnEditStep="GoToStep" OnBack="GoBack" OnSubmit="HandleSubmit" />
                break;
        }
    </div>
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    // Step 1
    private string fullName = string.Empty;
    private string email = string.Empty;
    private string phone = string.Empty;
    private string address = string.Empty;

    // Step 2
    private List<WorkHistoryStep.WorkEntryModel> workEntries = new() { new() };

    // Step 3
    private List<ReferencesStep.ReferenceModel> references = new() { new(), new() };

    // Step 4
    private string coverLetter = string.Empty;

    // Submission
    private bool isSubmitting;
    private bool isSubmitted;
    private int applicationId;

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }

    private void GoBack()
    {
        if (currentStep > 1)
            currentStep--;
    }

    private void HandlePersonalInfoNext(PersonalInfoStep.PersonalInfoResult result)
    {
        fullName = result.FullName;
        email = result.Email;
        phone = result.Phone;
        address = result.Address;
        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleWorkHistoryNext(List<WorkHistoryStep.WorkEntryModel> entries)
    {
        workEntries = entries;
        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleReferencesNext(List<ReferencesStep.ReferenceModel> refs)
    {
        references = refs;
        completedSteps.Add(3);
        currentStep = 4;
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        completedSteps.Add(4);
        currentStep = 5;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;

        var application = new JobApplication(
            new PersonalInfo(fullName, email, phone, address),
            new WorkHistory(workEntries.Select(e =>
                new WorkEntry(e.Company, e.Title, e.StartDate!.Value, e.EndDate, e.Description)).ToList()),
            references.Select(r =>
                new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitting = false;
        isSubmitted = true;
    }
}

